import { MultimodalChatbotScreen } from "@/components/multimodal-chatbot/multimodal-chatbot-screen";

export default function MultimodalChatbotPage() {
  return <MultimodalChatbotScreen />;
}

import { handleMultimodalChatbotRequest } from "@/lib/multimodal-chatbot/runtime";

export const runtime = "nodejs";

export function POST(request: Request) {
  return handleMultimodalChatbotRequest(request);
}

"use client";

import {
  ArrowClockwiseIcon,
  ImagesIcon,
  PaperclipIcon,
  StopIcon,
  XIcon,
} from "@phosphor-icons/react";
import {
  Attachment,
  AttachmentInfo,
  AttachmentPreview,
  AttachmentRemove,
  Attachments,
} from "@/components/ai-elements/attachments";
import {
  Conversation,
  ConversationContent,
  ConversationEmptyState,
  ConversationScrollButton,
} from "@/components/ai-elements/conversation";
import {
  Message,
  MessageContent,
  MessageResponse,
} from "@/components/ai-elements/message";
import {
  PromptInput,
  PromptInputBody,
  PromptInputFooter,
  PromptInputSubmit,
  PromptInputTextarea,
} from "@/components/ai-elements/prompt-input";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import type { ChatStatus, UIMessage } from "ai";
import type { RefObject } from "react";

import {
  getMultimodalFileParts,
  getMultimodalMessageText,
  type PendingAttachment,
} from "./multimodal-chatbot-session";
import { useMultimodalChatbotWorkspace } from "./use-multimodal-chatbot-workspace";

export interface MultimodalChatbotWorkspaceProps {
  acceptedMediaTypes: string[];
  chatModel: string;
  isChatAvailable: boolean;
  nodeVersion: string;
  setupMessage: string | null;
}

interface MultimodalConversationProps {
  hasMessages: boolean;
  messages: UIMessage[];
}

function MultimodalConversation({
  hasMessages,
  messages,
}: MultimodalConversationProps) {
  return (
    <Conversation className="min-h-0">
      <ConversationContent className="mx-auto flex w-full max-w-3xl flex-1 gap-6 px-4 py-6">
        {hasMessages ? (
          messages.map((message) => (
            <MultimodalMessage key={message.id} message={message} />
          ))
        ) : (
          <ConversationEmptyState
            description="Attach an image or PDF, ask a question, and inspect how the same chat surface handles ad-hoc multimodal context without preindexing."
            icon={<ImagesIcon className="size-5" />}
            title="Multi-modal workspace is ready"
          />
        )}
      </ConversationContent>
      <ConversationScrollButton />
    </Conversation>
  );
}

function MultimodalMessage({ message }: { message: UIMessage }) {
  const text = getMultimodalMessageText(message);
  const fileParts = getMultimodalFileParts(message);

  return (
    <Message from={message.role}>
      <MessageContent
        className={cn(
          "space-y-4",
          message.role === "assistant" ? "max-w-3xl" : "max-w-2xl"
        )}
      >
        {text ? <MessageResponse>{text}</MessageResponse> : null}

        {fileParts.length > 0 ? (
          <Attachments variant="list">
            {fileParts.map((part) => {
              const attachmentId = `${message.id}-${part.filename ?? "attachment"}-${part.url}`;

              return (
                <Attachment
                  data={{
                    ...part,
                    id: attachmentId,
                  }}
                  key={attachmentId}
                >
                  <AttachmentPreview />
                  <AttachmentInfo showMediaType />
                </Attachment>
              );
            })}
          </Attachments>
        ) : null}

        {!text && fileParts.length === 0 ? (
          <p className="text-muted-foreground text-sm">
            Waiting for visible output.
          </p>
        ) : null}
      </MessageContent>
    </Message>
  );
}

interface MultimodalComposerProps {
  chatModel: string;
  fileInputRef: RefObject<HTMLInputElement | null>;
  hasMessages: boolean;
  isBusy: boolean;
  isChatAvailable: boolean;
  onAppendFiles: (fileList: FileList | null) => void;
  onRegenerateLastTurn: () => void;
  onRemovePendingAttachment: (attachmentId: string) => void;
  onSend: (text: string) => Promise<void>;
  onSendSamplePrompt: (text: string) => void;
  onStopChat: () => void;
  pendingAttachments: PendingAttachment[];
  samplePrompts: readonly string[];
  status: ChatStatus;
}

function MultimodalComposer({
  chatModel,
  fileInputRef,
  hasMessages,
  isBusy,
  isChatAvailable,
  pendingAttachments,
  samplePrompts,
  status,
  onAppendFiles,
  onRegenerateLastTurn,
  onRemovePendingAttachment,
  onSend,
  onSendSamplePrompt,
  onStopChat,
}: MultimodalComposerProps) {
  return (
    <div className="border-foreground/10 border-t px-4 py-4">
      <div className="mx-auto w-full max-w-3xl">
        <PromptInput
          onSubmit={({ text }) => {
            onSend(text);
          }}
        >
          <PromptInputBody>
            <PendingAttachmentList
              attachments={pendingAttachments}
              onRemoveAttachment={onRemovePendingAttachment}
            />
            <PromptInputTextarea
              disabled={!isChatAvailable || isBusy}
              placeholder="Ask about an uploaded image or PDF. The message will carry the files inline to the model."
            />
          </PromptInputBody>
          <PromptInputFooter className="flex items-center justify-between gap-3 border-foreground/10 border-t px-3 py-3">
            <div className="flex flex-wrap items-center gap-2">
              <Badge variant="outline">Multimodal</Badge>
              <Badge variant="outline">Image + PDF</Badge>
              <Badge variant="outline">{chatModel}</Badge>
            </div>
            <div className="flex items-center gap-2">
              <input
                accept="image/*,application/pdf"
                className="sr-only"
                multiple
                onChange={(event) => onAppendFiles(event.target.files)}
                ref={fileInputRef}
                type="file"
              />
              <Button
                disabled={!isChatAvailable || isBusy}
                onClick={() => fileInputRef.current?.click()}
                size="sm"
                type="button"
                variant="outline"
              >
                <PaperclipIcon className="size-3.5" />
                Attach
              </Button>
              {isBusy ? (
                <Button
                  onClick={onStopChat}
                  size="sm"
                  type="button"
                  variant="outline"
                >
                  <StopIcon className="size-3.5" />
                  Stop
                </Button>
              ) : null}
              {hasMessages ? (
                <Button
                  onClick={onRegenerateLastTurn}
                  size="sm"
                  type="button"
                  variant="outline"
                >
                  <ArrowClockwiseIcon className="size-3.5" />
                  Retry
                </Button>
              ) : null}
              <PromptInputSubmit disabled={!isChatAvailable} status={status} />
            </div>
          </PromptInputFooter>
        </PromptInput>

        {hasMessages ? null : (
          <MultimodalSamplePrompts
            onSendSamplePrompt={onSendSamplePrompt}
            prompts={samplePrompts}
          />
        )}
      </div>
    </div>
  );
}

function PendingAttachmentList({
  attachments,
  onRemoveAttachment,
}: {
  attachments: PendingAttachment[];
  onRemoveAttachment: (attachmentId: string) => void;
}) {
  if (attachments.length === 0) {
    return null;
  }

  return (
    <Attachments className="mb-3" variant="list">
      {attachments.map((attachment) => (
        <Attachment
          data={{
            filename: attachment.file.name,
            id: attachment.id,
            mediaType: attachment.file.type,
            type: "file",
            url: attachment.previewUrl,
          }}
          key={attachment.id}
          onRemove={() => onRemoveAttachment(attachment.id)}
        >
          <AttachmentPreview />
          <AttachmentInfo showMediaType />
          <AttachmentRemove>
            <XIcon className="size-4" />
          </AttachmentRemove>
        </Attachment>
      ))}
    </Attachments>
  );
}

function MultimodalSamplePrompts({
  prompts,
  onSendSamplePrompt,
}: {
  prompts: readonly string[];
  onSendSamplePrompt: (text: string) => void;
}) {
  return (
    <div className="mt-3 flex flex-wrap gap-2">
      {prompts.map((prompt) => (
        <Button
          key={prompt}
          onClick={() => onSendSamplePrompt(prompt)}
          size="sm"
          type="button"
          variant="outline"
        >
          <ImagesIcon className="size-3.5" />
          {prompt}
        </Button>
      ))}
    </div>
  );
}

function MultimodalSidebar({
  acceptedMediaTypes,
  nodeVersion,
}: {
  acceptedMediaTypes: string[];
  nodeVersion: string;
}) {
  return (
    <aside className="border border-foreground/10 bg-background p-4 lg:min-h-0 lg:overflow-y-auto">
      <div className="space-y-4">
        <div>
          <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
            Runtime
          </p>
          <p className="mt-1 font-medium text-sm">{nodeVersion}</p>
        </div>
        <div>
          <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
            Input contract
          </p>
          <p className="mt-1 text-sm">
            This workspace sends image and PDF attachments inline as message
            parts, matching the official AI SDK multimodal guide.
          </p>
        </div>
        <div>
          <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
            Accepted media
          </p>
          <div className="mt-2 flex flex-wrap gap-2">
            {acceptedMediaTypes.map((mediaType) => (
              <Badge key={mediaType} variant="outline">
                {mediaType}
              </Badge>
            ))}
          </div>
        </div>
        <div>
          <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
            Demo role
          </p>
          <p className="mt-1 text-sm">
            Use this slice when users bring ad-hoc files into the chat and need
            model reasoning without an indexing pipeline.
          </p>
        </div>
      </div>
    </aside>
  );
}

export function MultimodalChatbotWorkspace({
  acceptedMediaTypes,
  chatModel,
  isChatAvailable,
  nodeVersion,
  setupMessage,
}: MultimodalChatbotWorkspaceProps) {
  const controller = useMultimodalChatbotWorkspace();

  return (
    <div className="grid min-h-[70svh] gap-4 lg:h-full lg:min-h-0 lg:grid-cols-[minmax(0,1fr)_20rem]">
      <section className="flex min-h-[70svh] flex-col border border-foreground/10 bg-background lg:h-full lg:min-h-0">
        {isChatAvailable ? null : (
          <div className="border-foreground/10 border-b px-4 py-3 text-muted-foreground text-xs/relaxed">
            {setupMessage}
          </div>
        )}

        {controller.chatErrorMessage ? (
          <div className="border-foreground/10 border-b px-4 py-3 text-destructive text-xs/relaxed">
            {controller.chatErrorMessage}
          </div>
        ) : null}

        {controller.composerError ? (
          <div className="border-foreground/10 border-b px-4 py-3 text-destructive text-xs/relaxed">
            {controller.composerError}
          </div>
        ) : null}

        <MultimodalConversation
          hasMessages={controller.hasMessages}
          messages={controller.messages}
        />
        <MultimodalComposer
          chatModel={chatModel}
          fileInputRef={controller.fileInputRef}
          hasMessages={controller.hasMessages}
          isBusy={controller.isBusy}
          isChatAvailable={isChatAvailable}
          onAppendFiles={controller.appendFiles}
          onRegenerateLastTurn={controller.regenerateLastTurn}
          onRemovePendingAttachment={controller.removePendingAttachment}
          onSend={controller.handleSend}
          onSendSamplePrompt={controller.sendSamplePrompt}
          onStopChat={controller.stopChat}
          pendingAttachments={controller.pendingAttachments}
          samplePrompts={controller.samplePrompts}
          status={controller.status}
        />
      </section>

      <MultimodalSidebar
        acceptedMediaTypes={acceptedMediaTypes}
        nodeVersion={nodeVersion}
      />
    </div>
  );
}

"use client";

import { Chat, useChat } from "@ai-sdk/react";
import { DefaultChatTransport, type UIMessage } from "ai";
import { useState } from "react";

export function useMultimodalChatbot() {
  const [chat] = useState(
    () =>
      new Chat<UIMessage>({
        transport: new DefaultChatTransport({
          api: "/api/demos/multimodal-chatbot",
        }),
      })
  );
  const controller = useChat({ chat });
  const hasMessages = controller.messages.length > 0;
  const isBusy =
    controller.status === "submitted" || controller.status === "streaming";

  return {
    ...controller,
    hasMessages,
    isBusy,
  };
}

"use client";

import type { ChatStatus, UIMessage } from "ai";
import {
  type RefObject,
  useCallback,
  useEffect,
  useRef,
  useState,
} from "react";

import { convertFilesToParts } from "./convert-files-to-parts";
import {
  buildPendingAttachmentId,
  mergePendingAttachments,
  multimodalSamplePrompts,
  type PendingAttachment,
} from "./multimodal-chatbot-session";
import { useMultimodalChatbot } from "./use-multimodal-chatbot";

interface UseMultimodalChatbotWorkspaceController {
  appendFiles: (fileList: FileList | null) => void;
  chatErrorMessage: string | null;
  composerError: string | null;
  fileInputRef: RefObject<HTMLInputElement | null>;
  handleSend: (text: string) => Promise<void>;
  hasMessages: boolean;
  isBusy: boolean;
  messages: UIMessage[];
  pendingAttachments: PendingAttachment[];
  regenerateLastTurn: () => void;
  removePendingAttachment: (attachmentId: string) => void;
  samplePrompts: readonly string[];
  sendSamplePrompt: (text: string) => void;
  status: ChatStatus;
  stopChat: () => void;
}

function buildPendingAttachment(file: File): PendingAttachment {
  return {
    file,
    id: buildPendingAttachmentId(file),
    previewUrl: URL.createObjectURL(file),
  };
}

function revokePendingAttachments(attachments: PendingAttachment[]) {
  for (const attachment of attachments) {
    URL.revokeObjectURL(attachment.previewUrl);
  }
}

function clearFileInput(input: HTMLInputElement | null) {
  if (input) {
    input.value = "";
  }
}

export function useMultimodalChatbotWorkspace(): UseMultimodalChatbotWorkspaceController {
  const [pendingAttachments, setPendingAttachments] = useState<
    PendingAttachment[]
  >([]);
  const [composerError, setComposerError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const pendingAttachmentsRef = useRef<PendingAttachment[]>([]);
  const {
    error,
    hasMessages,
    isBusy,
    messages,
    regenerate,
    sendMessage,
    status,
    stop,
  } = useMultimodalChatbot();

  useEffect(() => {
    pendingAttachmentsRef.current = pendingAttachments;
  }, [pendingAttachments]);

  useEffect(
    () => () => {
      revokePendingAttachments(pendingAttachmentsRef.current);
    },
    []
  );

  const clearPendingAttachments = useCallback(() => {
    setPendingAttachments((current) => {
      revokePendingAttachments(current);
      return [];
    });
  }, []);

  const appendFiles = useCallback((fileList: FileList | null) => {
    if (!fileList) {
      return;
    }

    const nextAttachments = Array.from(fileList).map(buildPendingAttachment);
    setPendingAttachments((current) => {
      const replacedIds = new Set(
        nextAttachments.map((attachment) => attachment.id)
      );

      revokePendingAttachments(
        current.filter((attachment) => replacedIds.has(attachment.id))
      );

      return mergePendingAttachments(current, nextAttachments);
    });
  }, []);

  const removePendingAttachment = useCallback((attachmentId: string) => {
    setPendingAttachments((current) => {
      const removedAttachment = current.find(
        (attachment) => attachment.id === attachmentId
      );

      if (removedAttachment) {
        URL.revokeObjectURL(removedAttachment.previewUrl);
      }

      return current.filter((attachment) => attachment.id !== attachmentId);
    });
  }, []);

  const handleSend = useCallback(
    async (text: string) => {
      const trimmedText = text.trim();

      if (!trimmedText && pendingAttachments.length === 0) {
        return;
      }

      try {
        setComposerError(null);
        const fileParts = await convertFilesToParts(
          pendingAttachments.map((attachment) => attachment.file)
        );
        const parts = trimmedText
          ? [{ type: "text" as const, text: trimmedText }, ...fileParts]
          : fileParts;

        sendMessage({
          parts,
          role: "user",
        });
        clearPendingAttachments();
        clearFileInput(fileInputRef.current);
      } catch (attachmentError) {
        setComposerError(
          attachmentError instanceof Error
            ? attachmentError.message
            : "Failed to prepare attachments."
        );
      }
    },
    [clearPendingAttachments, pendingAttachments, sendMessage]
  );

  const sendSamplePrompt = useCallback(
    (text: string) => {
      sendMessage({ text });
    },
    [sendMessage]
  );

  return {
    chatErrorMessage: error?.message ?? null,
    composerError,
    fileInputRef,
    hasMessages,
    isBusy,
    messages,
    pendingAttachments,
    samplePrompts: multimodalSamplePrompts,
    status,
    appendFiles,
    handleSend,
    regenerateLastTurn: regenerate,
    removePendingAttachment,
    sendSamplePrompt,
    stopChat: stop,
  };
}

export function convertFilesToParts(files: File[]) {
  return Promise.all(
    files.map(
      (file) =>
        new Promise<{
          filename: string;
          mediaType: string;
          type: "file";
          url: string;
        }>((resolve, reject) => {
          const reader = new FileReader();

          reader.onload = () => {
            const result = reader.result;

            if (typeof result !== "string") {
              reject(new Error(`Failed to read ${file.name} as a data URL.`));
              return;
            }

            resolve({
              filename: file.name,
              mediaType: file.type || "application/octet-stream",
              type: "file",
              url: result,
            });
          };

          reader.onerror = () => {
            reject(new Error(`Failed to read ${file.name} as a data URL.`));
          };

          reader.readAsDataURL(file);
        })
    )
  );
}

import type { FileUIPart, UIMessage } from "ai";

export interface PendingAttachment {
  file: File;
  id: string;
  previewUrl: string;
}

export const multimodalSamplePrompts = [
  "Summarize the uploaded PDF in three bullets.",
  "What stands out in this image?",
  "Compare the text in the PDF with the diagram screenshot.",
] as const;

export function getMultimodalMessageText(message: UIMessage) {
  return message.parts
    .filter((part) => part.type === "text")
    .map((part) => part.text)
    .join("\n");
}

export function getMultimodalFileParts(message: UIMessage) {
  return message.parts.filter(
    (part): part is FileUIPart => part.type === "file"
  );
}

export function buildPendingAttachmentId(
  file: Pick<File, "lastModified" | "name" | "size">
) {
  return `${file.name}-${file.size}-${file.lastModified}`;
}

export function mergePendingAttachments(
  current: PendingAttachment[],
  next: PendingAttachment[]
) {
  const byId = new Map(
    current.map((attachment) => [attachment.id, attachment])
  );

  for (const attachment of next) {
    byId.set(attachment.id, attachment);
  }

  return Array.from(byId.values());
}

"use client";

import { CornerDownLeftIcon, LoaderCircleIcon, SquareIcon } from "lucide-react";
import type {
  ComponentProps,
  FormEvent,
  HTMLAttributes,
  ReactNode,
  TextareaHTMLAttributes,
} from "react";
import {
  createContext,
  useCallback,
  useContext,
  useMemo,
  useState,
} from "react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { cn } from "@/lib/utils";

type PromptStatus = "error" | "ready" | "streaming" | "submitted";

interface PromptInputContextValue {
  setText: (text: string) => void;
  text: string;
}

interface PromptInputMessage {
  text: string;
}

interface PromptInputProps
  extends Omit<HTMLAttributes<HTMLFormElement>, "onSubmit"> {
  children: ReactNode;
  onSubmit: (
    message: PromptInputMessage,
    event: FormEvent<HTMLFormElement>
  ) => void | Promise<void>;
}

interface PromptInputSubmitProps
  extends Omit<ComponentProps<typeof Button>, "children" | "type"> {
  onStop?: () => void;
  status?: PromptStatus;
}

type PromptInputClickEvent = Parameters<
  Exclude<ComponentProps<typeof Button>["onClick"], undefined>
>[0];

const PromptInputContext = createContext<PromptInputContextValue | null>(null);

function usePromptInputContext() {
  const context = useContext(PromptInputContext);

  if (!context) {
    throw new Error(
      "PromptInput components must be used inside <PromptInput>."
    );
  }

  return context;
}

export function PromptInput({
  children,
  className,
  onSubmit,
  ...props
}: PromptInputProps) {
  const [text, setText] = useState("");

  const contextValue = useMemo(
    () => ({
      setText,
      text,
    }),
    [text]
  );

  const handleSubmit = useCallback(
    async (event: FormEvent<HTMLFormElement>) => {
      event.preventDefault();

      const nextText = text.trim();
      if (!nextText) {
        return;
      }

      const result = onSubmit({ text: nextText }, event);

      try {
        await result;
        setText("");
      } catch {
        // Keep the text for retry after a failed submit.
      }
    },
    [onSubmit, text]
  );

  return (
    <PromptInputContext.Provider value={contextValue}>
      <form
        className={cn("w-full", className)}
        onSubmit={handleSubmit}
        {...props}
      >
        {children}
      </form>
    </PromptInputContext.Provider>
  );
}

export function PromptInputBody({
  className,
  ...props
}: HTMLAttributes<HTMLDivElement>) {
  return <div className={cn("grid gap-3", className)} {...props} />;
}

export function PromptInputFooter({
  className,
  ...props
}: HTMLAttributes<HTMLDivElement>) {
  return <div className={cn(className)} {...props} />;
}

export function PromptInputTextarea({
  className,
  disabled,
  onChange,
  ...props
}: TextareaHTMLAttributes<HTMLTextAreaElement>) {
  const context = usePromptInputContext();

  return (
    <Textarea
      className={cn("min-h-16 resize-none", className)}
      disabled={disabled}
      onChange={(event) => {
        context.setText(event.currentTarget.value);
        onChange?.(event);
      }}
      value={context.text}
      {...props}
    />
  );
}

export function PromptInputSubmit({
  className,
  disabled,
  onClick,
  onStop,
  size = "icon",
  status = "ready",
  variant = "default",
  ...props
}: PromptInputSubmitProps) {
  const { text } = usePromptInputContext();
  const isBusy = status === "submitted" || status === "streaming";
  const isDisabled = Boolean(disabled) || (!isBusy && text.trim().length === 0);

  let icon = <CornerDownLeftIcon className="size-4" />;

  if (status === "submitted") {
    icon = <LoaderCircleIcon className="size-4 animate-spin" />;
  } else if (status === "streaming") {
    icon = <SquareIcon className="size-4" />;
  }

  return (
    <Button
      aria-label={isBusy ? "Stop" : "Submit"}
      className={cn(className)}
      disabled={isDisabled}
      onClick={(event: PromptInputClickEvent) => {
        if (isBusy && onStop) {
          event.preventDefault();
          onStop();
          return;
        }

        onClick?.(event);
      }}
      size={size}
      type={isBusy && onStop ? "button" : "submit"}
      variant={variant}
      {...props}
    >
      {icon}
    </Button>
  );
}

import { createGateway } from "ai";

const DEFAULT_GATEWAY_BASE_URL = "https://ai-gateway.vercel.sh/v3/ai";
const DEFAULT_CHAT_MODEL = "openai/gpt-4.1-mini";
const MINIMUM_NODE_VERSION = "22.13.0";
const nodeVersionPattern = /^v?(\d+)\.(\d+)\.(\d+)(?:[-+].*)?$/;

interface ParsedNodeVersion {
  major: number;
  minor: number;
  patch: number;
}

export type MultimodalChatbotEnv = Record<string, string | undefined>;

export interface MultimodalChatbotConfig {
  apiKey: string;
  baseURL: string;
  chatModel: string;
}

export interface MultimodalChatbotSetupState {
  config: Omit<MultimodalChatbotConfig, "apiKey">;
  isReady: boolean;
  issues: string[];
  nodeVersion: string;
}

function parseNodeVersion(version: string): ParsedNodeVersion {
  const match = nodeVersionPattern.exec(version);
  const major = Number(match?.[1]);
  const minor = Number(match?.[2]);
  const patch = Number(match?.[3]);

  if (![major, minor, patch].every(Number.isInteger)) {
    throw new Error(`Unable to parse Node.js version: "${version}".`);
  }

  return { major, minor, patch };
}

function compareNodeVersions(
  left: ParsedNodeVersion,
  right: ParsedNodeVersion
) {
  if (left.major !== right.major) {
    return left.major - right.major;
  }

  if (left.minor !== right.minor) {
    return left.minor - right.minor;
  }

  return left.patch - right.patch;
}

function assertSupportedNodeRuntime(version = process.version) {
  const parsedVersion = parseNodeVersion(version);
  const minimumVersion = parseNodeVersion(MINIMUM_NODE_VERSION);

  if (compareNodeVersions(parsedVersion, minimumVersion) < 0) {
    throw new Error(
      `Node.js ${version} is unsupported. This demo workspace requires Node.js >=${MINIMUM_NODE_VERSION}.`
    );
  }
}

export function getMultimodalChatbotEnv(): MultimodalChatbotEnv {
  // biome-ignore lint/style/noProcessEnv: Registry source installs into consumer apps without this repo's env wrapper.
  return process.env;
}

function readRequiredEnv(
  env: MultimodalChatbotEnv,
  name: keyof MultimodalChatbotEnv
) {
  const value = env[name];

  if (!value) {
    throw new Error(
      `Missing ${name}. Add it to .env.local before using the multimodal chatbot.`
    );
  }

  return value;
}

function resolveMultimodalChatbotEnv(
  env: MultimodalChatbotEnv = getMultimodalChatbotEnv()
) {
  return {
    apiKey: env.AI_GATEWAY_API_KEY,
    baseURL: env.AI_GATEWAY_BASE_URL || DEFAULT_GATEWAY_BASE_URL,
    chatModel: env.AI_GATEWAY_CHAT_MODEL || DEFAULT_CHAT_MODEL,
  };
}

export function getMultimodalChatbotConfig(
  env: MultimodalChatbotEnv = getMultimodalChatbotEnv()
): MultimodalChatbotConfig {
  assertSupportedNodeRuntime();
  const resolvedEnv = resolveMultimodalChatbotEnv(env);

  return {
    apiKey: readRequiredEnv(env, "AI_GATEWAY_API_KEY"),
    baseURL: resolvedEnv.baseURL,
    chatModel: resolvedEnv.chatModel,
  };
}

export function getMultimodalChatbotSetupState(
  env: MultimodalChatbotEnv = getMultimodalChatbotEnv()
): MultimodalChatbotSetupState {
  const issues: string[] = [];
  const resolvedEnv = resolveMultimodalChatbotEnv(env);

  try {
    assertSupportedNodeRuntime();
  } catch (error) {
    issues.push(
      error instanceof Error ? error.message : "Unsupported Node.js runtime."
    );
  }

  if (!resolvedEnv.apiKey) {
    issues.push(
      "AI_GATEWAY_API_KEY is missing. The demo can render, but multimodal chat requests will fail until it is configured."
    );
  }

  return {
    config: {
      baseURL: resolvedEnv.baseURL,
      chatModel: resolvedEnv.chatModel,
    },
    isReady: issues.length === 0,
    issues,
    nodeVersion: process.version,
  };
}

export function createMultimodalChatbotGateway(
  env: MultimodalChatbotEnv = getMultimodalChatbotEnv()
) {
  const { apiKey, baseURL } = getMultimodalChatbotConfig(env);

  return createGateway({
    apiKey,
    baseURL,
  });
}

import {
  convertToModelMessages,
  streamText,
  type UIMessage,
  validateUIMessages,
} from "ai";

import {
  createMultimodalChatbotGateway,
  getMultimodalChatbotConfig,
  getMultimodalChatbotEnv,
  getMultimodalChatbotSetupState,
  type MultimodalChatbotEnv,
} from "@/lib/multimodal-chatbot/env";

const invalidMessagesError = 'Expected a JSON body with a "messages" array.';
const invalidUiMessagesError =
  'Expected each "messages" entry to match the UIMessage format.';
const malformedJsonError = "Expected a valid JSON request body.";
const unsupportedMediaTypeError =
  "Only image attachments and PDF attachments are supported.";

interface MultimodalChatbotRequestBody {
  messages?: UIMessage[];
}

export interface MultimodalChatbotRuntimeState {
  acceptedMediaTypes: string[];
  chatModel: string;
  isChatAvailable: boolean;
  nodeVersion: string;
  setupMessage: string | null;
  statusLabel: "Ready" | "Setup required";
}

interface MultimodalChatbotRequestDependencies {
  streamMultimodalChatbot: (
    messages: UIMessage[],
    env: MultimodalChatbotEnv
  ) => Promise<Response>;
}

const acceptedMediaTypes = ["application/pdf", "image/*"] as const;

export function getMultimodalChatbotRuntimeState(
  env: MultimodalChatbotEnv = getMultimodalChatbotEnv()
): MultimodalChatbotRuntimeState {
  const setup = getMultimodalChatbotSetupState(env);

  return {
    acceptedMediaTypes: [...acceptedMediaTypes],
    chatModel: setup.config.chatModel,
    isChatAvailable: setup.isReady,
    nodeVersion: setup.nodeVersion,
    setupMessage: setup.issues.length > 0 ? setup.issues.join(" ") : null,
    statusLabel: setup.isReady ? "Ready" : "Setup required",
  };
}

function assertAcceptedMediaTypes(messages: UIMessage[]) {
  for (const message of messages) {
    for (const part of message.parts) {
      if (part.type !== "file") {
        continue;
      }

      const mediaType = part.mediaType ?? "";
      const isAccepted =
        mediaType.startsWith("image/") || mediaType === "application/pdf";

      if (!isAccepted) {
        throw new Error(unsupportedMediaTypeError);
      }
    }
  }
}

async function readMultimodalChatbotMessages(
  body: unknown
): Promise<UIMessage[]> {
  const { messages } = (body ?? {}) as MultimodalChatbotRequestBody;

  if (!Array.isArray(messages)) {
    throw new Error(invalidMessagesError);
  }

  try {
    const validatedMessages = await validateUIMessages({ messages });
    assertAcceptedMediaTypes(validatedMessages);
    return validatedMessages;
  } catch (error) {
    if (error instanceof Error && error.message === unsupportedMediaTypeError) {
      throw error;
    }

    throw new Error(invalidUiMessagesError);
  }
}

export async function streamMultimodalChatbot(
  messages: UIMessage[],
  env: MultimodalChatbotEnv
) {
  const gateway = createMultimodalChatbotGateway(env);
  const { chatModel } = getMultimodalChatbotConfig(env);

  const result = streamText({
    model: gateway(chatModel),
    messages: await convertToModelMessages(messages),
  });

  return result.toUIMessageStreamResponse();
}

export async function handleMultimodalChatbotRequest(
  request: Request,
  env: MultimodalChatbotEnv = getMultimodalChatbotEnv(),
  dependencies: MultimodalChatbotRequestDependencies = {
    streamMultimodalChatbot,
  }
) {
  const runtimeState = getMultimodalChatbotRuntimeState(env);

  if (!runtimeState.isChatAvailable) {
    return Response.json(
      {
        error: runtimeState.setupMessage,
      },
      { status: 500 }
    );
  }

  let messages: UIMessage[];

  try {
    messages = await readMultimodalChatbotMessages(await request.json());
  } catch (error) {
    if (error instanceof SyntaxError) {
      return Response.json(
        {
          error: malformedJsonError,
        },
        { status: 400 }
      );
    }

    if (
      error instanceof Error &&
      [
        invalidMessagesError,
        invalidUiMessagesError,
        unsupportedMediaTypeError,
      ].includes(error.message)
    ) {
      return Response.json(
        {
          error: error.message,
        },
        { status: 400 }
      );
    }

    throw error;
  }

  return dependencies.streamMultimodalChatbot(messages, env);
}
